if(CKEDITOR.instances[textarea.id]){try{CKEDITOR.instances[textarea.id].destroy(!0)}catch(e){}}
const height=parseInt(this.getAttribute('height')||'300',10);const mode=this.getAttribute('mode')||'full';const customCss=this.getAttribute('custom-css')||'';const allowBr=this.hasAttribute('allow-br');const isSimple=mode==='simple';const isMinimal=mode==='minimal';const globalConfig=CMA.formConfig?.editorConfig||{};const config=this._buildConfig({height,mode,allowBr:allowBr||globalConfig.allowBR||!1,extraPlugins:globalConfig.extraPlugins||'',isSimple,isMinimal});try{this._editor=CKEDITOR.replace(textarea,config)}catch(e){cmaLog.error('[cma-htmledit] CKEDITOR.replace failed for "'+name+'":',e.message);return}
